// Create a Map with string keys (product) and number values (quantity)
const inventory: Map<string, number> = new Map();
// Add products to the inventory
inventory.set('Laptop', 15);
inventory.set('Mouse', 42);
inventory.set('Keyboard', 28);
// Update an existing product's quantity
inventory.set('Mouse', inventory.get('Mouse')! + 10);
// Check if a product exists and get its quantity
const laptopStock: number | undefined = inventory.get('Laptop');
console.log('Laptop stock:', laptopStock);
// Iterate over all entries
inventory.forEach((quantity, product) => {
  console.log(`${product}: ${quantity} units`);
});
// Check if product exists
console.log('Has Tablet?', inventory.has('Tablet'));
// Expected:
// Laptop stock: 15
// Laptop: 15 units
// Mouse: 52 units
// Keyboard: 28 units
// Has Tablet? false
